# ── σ-block-diagonal mask helpers ──────────────────────────────────────────

def _block_diagonal_mask(in_mask: list, out_mask: list) -> torch.Tensor:
    """Build the (len(out_mask), len(in_mask)) binary mask where entry
    [i, j] = 1 iff out_mask[i] == in_mask[j]. Weights with mask==0 are
    forced to zero by σ-equivariance."""
    return torch.tensor(
        [[1.0 if out_mask[i] == in_mask[j] else 0.0
          for j in range(len(in_mask))]
         for i in range(len(out_mask))],
        dtype=torch.float32,
    )

def _sigma_mask_64x64() -> torch.Tensor:
    return _block_diagonal_mask(SIGMA64_MASK, SIGMA64_MASK)

def _sigma_mask_for_head(out_slice: slice) -> torch.Tensor:
    """Mask for a decoder head whose output dims are SIGMA768_MASK[out_slice]."""
    return _block_diagonal_mask(SIGMA64_MASK, SIGMA768_MASK[out_slice])

# ── L3 encoder: per-token MLP (10 → 64), then sum-pool over tokens ─────────

class L3Encoder(nn.Module):
    """Permutation-invariant set encoder. σ-equivariance is enforced by
    aligning the trained projection's structure to GMM_TOKEN_SIGMA_MASK ↔
    SIGMA64_MASK. The reference baseline ('placeToken' in LookNetE.hs) is
    the σ-correct skeleton this layer extends with learned mixing."""

    def __init__(self):
        super().__init__()
        # Per-token expansion 10 → 128 (no σ constraint at the intermediate
        # layer — the trainer learns the embedding subject to the boundary
        # masks below).
        self.phi1 = nn.Linear(GMM_TOKEN_DIM, 128, bias=True)
        # Final projection 128 → 64 with σ-block-diagonal mask at the output
        # boundary: each output dim's σ-class (SIGMA64_MASK) constrains which
        # input dims contribute. The 128-D intermediate's σ-classes are split
        # 50/50 (first 64 σ-fixed, last 64 σ-negated) so the mask is dense
        # on its half and zero on its cross-half.
        self.phi2 = nn.Linear(128, MODEL_DIM, bias=False)
        inter_mask = [False] * 64 + [True] * 64
        self.register_buffer(
            "phi2_mask",
            _block_diagonal_mask(inter_mask, SIGMA64_MASK),
        )

    def forward(self, tokens: torch.Tensor, token_mask: torch.Tensor = None) -> torch.Tensor:
        # tokens: (B, MAX_TOKENS, 10);  token_mask: (B, MAX_TOKENS) in {0, 1}
        h = F.gelu(self.phi1(tokens))             # (B, MAX_TOKENS, 128)
        w2 = self.phi2.weight * self.phi2_mask    # σ-mask applied
        h = F.linear(h, w2)                       # (B, MAX_TOKENS, 64)
        if token_mask is not None:
            h = h * token_mask.unsqueeze(-1)
        return h.sum(dim=1)                       # (B, 64) — sum-pool (perm-invariant)

# ── L4 core: 8 unrolled residual blocks with σ-block-diagonal weights ──────

class L4Block(nn.Module):
    """One residual block x ↦ x + (1-h) · φ(x). φ is a two-layer MLP whose
    weight matrices are σ-block-diagonal-constrained: only intra-σ-class
    weights are free (22²+42² = 2248 out of 4096 per matrix, ≈45% pruned
    by symmetry — see LookNetR.lawSymmetryPruningRatio)."""

    def __init__(self):
        super().__init__()
        self.w1 = nn.Linear(MODEL_DIM, MODEL_DIM, bias=False)
        self.w2 = nn.Linear(MODEL_DIM, MODEL_DIM, bias=False)
        # Learned halting scalar in [0, 1] (sigmoid-clamped); Graves-ACT
        # amortized into per-block weights — no control flow at inference.
        self.halting_logit = nn.Parameter(torch.zeros(1))
        self.register_buffer("sigma_mask", _sigma_mask_64x64())

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        w1 = self.w1.weight * self.sigma_mask
        w2 = self.w2.weight * self.sigma_mask
        dx = F.gelu(F.linear(x, w1))
        dx = F.linear(dx, w2)
        scale = 1.0 - torch.sigmoid(self.halting_logit)
        return x + scale * dx

class L4Core(nn.Module):
    """CORE_DEPTH unrolled L4Blocks (fixed at 8 = paletteDepth)."""

    def __init__(self):
        super().__init__()
        self.blocks = nn.ModuleList([L4Block() for _ in range(CORE_DEPTH)])

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        for blk in self.blocks:
            x = blk(x)
        return x

# ── L5 decoder: per-level Haar heads with σ-block-diagonal weights ─────────

class L5Decoder(nn.Module):
    """Nine parallel heads (root + 8 Haar levels) from the 64-D hidden state
    to the 768-D flat Haar output. Each head is σ-block-diagonal-constrained
    against the corresponding slice of SIGMA768_MASK. Sum of head sizes =
    sum(DECODER_LEVEL_DIMS) = 768."""

    def __init__(self):
        super().__init__()
        self.heads = nn.ModuleList()
        offsets = []
        cur = 0
        for d in DECODER_LEVEL_DIMS:
            self.heads.append(nn.Linear(MODEL_DIM, d, bias=False))
            offsets.append((cur, cur + d))
            cur += d
        self.offsets = offsets
        for i, (lo, hi) in enumerate(offsets):
            self.register_buffer(
                f"head_mask_{i}",
                _sigma_mask_for_head(slice(lo, hi)),
            )

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        outs = []
        for i, head in enumerate(self.heads):
            mask = getattr(self, f"head_mask_{i}")
            w = head.weight * mask
            outs.append(F.linear(x, w))
        return torch.cat(outs, dim=-1)             # (B, 768)

# ── The full pipeline ──────────────────────────────────────────────────────

class LookNet(nn.Module):
    """E :> R :> D, proven σ-equivariant end-to-end by
    SixFour.Spec.LookNetCompose.lookNetSigmaTheorem."""

    def __init__(self):
        super().__init__()
        self.encoder = L3Encoder()
        self.core    = L4Core()
        self.decoder = L5Decoder()

    def forward(self, tokens: torch.Tensor, token_mask: torch.Tensor = None) -> torch.Tensor:
        h = self.encoder(tokens, token_mask=token_mask)   # (B, 64)
        h = self.core(h)                                  # (B, 64)
        return self.decoder(h)                            # (B, 768)
